:root {
  --bg-color: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --border: #e0e0e0;
  --light-bg: #f8f9fa;
  --boundary-high: #e74c3c;
  --exposure-layer: #e67e22;
  --data-source: #3498db;
  --context-node: #95a5a6;
}

body {
  margin: 0;
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: transparent;
}

.diagram-card {
  background: var(--bg-color);
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  border: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  height: 100vh;
}

.header {
  padding: 15px 20px;
  border-bottom: 1px solid var(--border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: var(--light-bg);
}

.header h3 {
  margin: 0;
  color: var(--primary);
  font-size: 1.1rem;
}

.tag {
  background: var(--exposure-layer);
  color: white;
  padding: 2px 8px;
  border-radius: 4px;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.content-wrapper {
  display: flex;
  flex: 1;
  overflow: hidden;
}

.image-container {
  flex: 2;
  padding: 20px;
  background: #ffffff;
  display: flex;
  align-items: center;
  justify-content: center;
  border-right: 1px solid var(--border);
  overflow: auto;
}

img {
  max-width: 100%;
  max-height: 100%;
  object-fit: contain;
  border-radius: 4px;
  transition: transform 0.2s;
}

img:hover {
  transform: scale(1.02);
}

.info-panel {
  flex: 1;
  padding: 20px;
  background: var(--light-bg);
  display: flex;
  flex-direction: column;
  overflow-y: auto;
}

.info-panel h4 {
  margin-top: 0;
  color: var(--primary);
  border-bottom: 2px solid var(--accent);
  padding-bottom: 8px;
  margin-bottom: 15px;
}

.info-panel p {
  color: #555;
  line-height: 1.6;
  font-size: 0.95rem;
  background: #fff;
  padding: 15px;
  border-radius: 6px;
  border: 1px solid var(--border);
}

.legend {
  margin-top: auto;
  padding-top: 20px;
}

.legend-item {
  display: flex;
  align-items: center;
  margin-bottom: 10px;
  font-size: 0.85rem;
  color: #444;
}

.legend-item b {
  margin-right: 5px;
  color: var(--primary);
}

.dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  margin-right: 10px;
  flex-shrink: 0;
}

/* Node Taxonomy Colors */
.source {
  background-color: var(--data-source);
}

.transform {
  background-color: var(--context-node);
}

.boundary {
  background-color: var(--exposure-layer);
}

.sink {
  background-color: var(--boundary-high);
}

.icon {
  margin-right: 5px;
}

@media (max-width: 768px) {
  .content-wrapper {
    flex-direction: column;
  }
  .image-container {
    border-right: none;
    border-bottom: 1px solid var(--border);
    min-height: 300px;
  }
}

srcDoc.js:
appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const imgElement = document.getElementById('diagram-img');
    const textElement = document.getElementById('explanation-text');

    // 1. APPLY TO IMAGE
    if (model.queryData && model.queryData.length > 30) {
      imgElement.src = model.queryData;
    } else {
      imgElement.alt = "Waiting for Exposure Map data...";
    }

    // 2. APPLY TEXT
    if (model.explanation) {
      textElement.innerHTML = model.explanation;
    }
  });
});

